// src/App.jsx
import React from "react";
import { RouterProvider, useRouter } from "./context/RouterContext";
import { AuthProvider, useAuth } from "./components/auth/AuthContext";
import { LoginPage } from "./components/auth/LoginPage";
import { ChangePasswordPage } from "./components/auth/ChangePasswordPage";
import { StudentDashboard } from "./components/student/StudentDashboard";
import { CoordinatorDashboard } from "./components/coordinator/CoordinatorDashboard";
import { FacultyDashboard } from "./components/faculty/FacultyDashboard";
import { AdminDashboard } from "./components/admin/AdminDashboard";
import { DirectorDashboard } from "./components/director/DirectorDashboard";
import { EADashboard } from "./components/ea/EADashboard";
import { VisitingFacultyDashboard } from "./components/visiting_faculty/VisitingFacultyDashboard";

// Main App Router Component
function AppRouter() {
  const { route, navigate } = useRouter();
  const { user } = useAuth();

  // Debug logging (remove in production)
  React.useEffect(() => {
    console.log("=== AppRouter Debug ===");
    console.log("Current route:", route);
    console.log("Current user:", user);
    console.log("Password changed:", user?.passwordChanged);
  }, [route, user]);

  // If user exists and password is not changed, force change-password page
  if (user && !user.passwordChanged && route !== "change-password") {
    console.log("Redirecting to change-password page");
    navigate("change-password");
    return <ChangePasswordPage />;
  }

  // If no user and not on login page, redirect to login
  if (!user && route !== "login") {
    console.log("No user found, redirecting to login");
    navigate("login");
    return <LoginPage />;
  }

  // Handle routing based on route
  switch(route) {
    case "login":
      return <LoginPage />;
    
    case "change-password":
      return <ChangePasswordPage />;
    
    case "faculty":
      return <FacultyDashboard />;
    
    case "coordinator":
      return <CoordinatorDashboard />;
    
    case "admin":
      return <AdminDashboard />;
    
    case "director":
      return <DirectorDashboard />;
    
    case "ea":
      return <EADashboard />;
    
    case "visiting_faculty":
      return <VisitingFacultyDashboard />;
    
    case "student":
      return <StudentDashboard />;
    
    default:
      // If user exists but route is invalid, navigate to their dashboard
      if (user) {
        let targetRoute;
        switch(user.role) {
          case "admin":
            targetRoute = "admin";
            break;
          case "coordinator":
            targetRoute = "coordinator";
            break;
          case "faculty":
            targetRoute = "faculty";
            break;
          case "director":
            targetRoute = "director";
            break;
          case "ea":
            targetRoute = "ea";
            break;
          case "visiting_faculty":
            targetRoute = "visiting_faculty";
            break;
          default:
            targetRoute = "student";
        }
        console.log("Invalid route, navigating to:", targetRoute);
        navigate(targetRoute);
        return null;
      }
      return <LoginPage />;
  }
}

// Main App Component
export default function AcadPlanApp() {
  return (
    <RouterProvider>
      <AuthProvider>
        <AppRouter />
      </AuthProvider>
    </RouterProvider>
  );
}